UPDATE hpeapm.audit_elements_data_support_v2
SET isdel=0
where audit_model_number = #{auditModelNumber}

mapper.select:
SELECT id, audit_model_number, assetCode, "code", "name", originalSystemcode, originalSystem, interId, interName, objLevelCode, busiType, is_acc AS is_acc, "status" AS "status", data_supporter FROM hpeapm."audit_elements_data_support_v2" WHERE 1 = 1
AND audit_model_number LIKE CONCAT('%', #{auditModelNumber}, '%')
AND isdel=1;

SELECT DISTINCT
assetCode AS "label",
assetCode AS "value"
FROM
hpeapm."audit_assets_data"
where 1=1

    AND code=#{dataCode}


    AND "name"=#{name}


    AND originalSystemcode=#{originalSystemcode}


    AND originalSystem=#{originalSystem}


    AND interId=#{interId}


    AND interName=#{interName}


    AND objLevelCode=#{objLevelCode}


    AND busiType=#{busiType}


    AND status=#{dataStatus}

