SELECT a.*, b.sourcesAuditPractice AS sourcesAuditPractice FROM (SELECT a."primary_business_process" AS primaryBusinessProcess, a."secondary_business_process" AS secondaryBusinessProcess, a."audit_point_name" auditPointName, a."audit_point_number" auditPointNumber, a."audit_model_name" auditModelName, a."audit_model_number" auditModelNumber, b."assetCode" AS assetCode, b."code" AS "code", b."name" AS "name", b."originalSystemcode" AS originalSystemcode, b."originalSystem" originalSystem, b."interId" interId, b."interName" interName FROM hpeapm."audit_elements_info" a LEFT JOIN hpeapm."audit_elements_data_support_v2" b ON a."audit_model_number" = b."audit_model_number" WHERE b."isdel" = '1'
AND a."audit_model_number" LIKE CONCAT('%', #{auditModelNumber}, '%')
AND a."audit_model_name" LIKE CONCAT('%', #{auditModelName}, '%')
AND a."primary_business_process"=#{primaryBusinessProcess}
AND a."secondary_business_process"=#{secondaryBusinessProcess}
AND b.assetCode=#{assetCode}
AND b.code LIKE CONCAT('%', #{code}, '%')
AND b.name LIKE CONCAT('%', #{name}, '%')
) a LEFT JOIN (SELECT sources_audit_practice AS sourcesAuditPractice, audit_model_number FROM hpeapm."audit_elements_online_model" WHERE is_deleted = '0' ) b ON a.auditModelNumber = b.audit_model_number

